import LocalErrorBoundary from "../../LocalErrorBoundary";
import {createRoot} from "react-dom/client";
import DivisionTiming from "./DivisionTiming";


declare global {
    interface Window {
        eventCode: string,
        eventName: string,
        divisionNames: string[]
    }
}

const container = document.getElementById('reactContainer');
if (!container) {
    console.error("Mount point for container not found")
} else {
    const root = createRoot(container);
    root.render(<LocalErrorBoundary>
        <a href={`/event/${window.eventCode}/`}>&lt;&lt; Back to Event Home</a>
        <h2 className={"text-center"}>Multi-Division Timing Status</h2>
        <h4 className={"text-center"}>{window.eventName}</h4>
        <DivisionTiming eventCode={window.eventCode} divisionNames={window.divisionNames}/>
    </LocalErrorBoundary>);
}