import {usePersistentWebsocketWithTime} from "ftc-common/utils";
import {MatchSorter} from "../../hr/TimingTab";
import {ActiveScheduleChange, Init, Match, MatchAbort, MatchCommit, MatchesCanceled, MatchesCreated, MatchLoad, MatchStarted, MatchState, MatchType, ScheduleUpdate, ScheduleUpdateType, TimeoutData} from "../../javaTypes";
import {useReducer} from "react";
import {TimeoutReference} from "ftc-common/javaTypes";
import MultiDivisionTimingTab from "../../hr/MultiDivisionTimingTab";

interface DivTimingUpdate {
    division: number,
    update: ScheduleUpdate
}

type MatchTimingData = {
    matchList: Match[];
    matchType: MatchType,
    nextMatch?: Match,
    timeouts: TimeoutReference[]
}

const defaultData: MatchTimingData = {
    matchList: [],
    matchType: MatchType.QUALS,
    timeouts: []
}

function updateDivData(current: Record<number, MatchTimingData>, update: DivTimingUpdate) {
    const division = update.division;
    const currentData = current[division] ? {...current[division]} : {...defaultData};

    switch (update.update.type) {
        case ScheduleUpdateType.INIT:
            const i = update.update as Init;
            currentData.matchList = i.matches;
            currentData.matchType = i.matchType;
            currentData.timeouts = i.timeoutData.activeTimeouts;
            currentData.nextMatch = i.timeoutData.assumedNext.length > 0 ? currentData.matchList.find(x => x.number === i.timeoutData.assumedNext[0]?.number) : undefined;
            break;
        case ScheduleUpdateType.MATCHES_CREATED:
            if ((update.update as MatchesCreated).matchType === currentData.matchType) {
                currentData.matchList.push(...(update.update as MatchesCreated).matches);
                currentData.matchList.sort(MatchSorter);
            } else {
                return currentData;
            }
            break;
        case ScheduleUpdateType.ACTIVE_SCHEDULE_CHANGE:
            currentData.matchList = (update.update as ActiveScheduleChange).matches;
            currentData.matchType = (update.update as ActiveScheduleChange).matchType;
            break;
        case ScheduleUpdateType.MATCHES_CANCELLED:
            const mc = update.update as MatchesCanceled;
            currentData.matchList = currentData.matchList.filter(x => x.type === mc.matchType && mc.numbers.includes(x.number))
            break;
        case ScheduleUpdateType.MATCH_STARTED:
            const s = update.update as MatchStarted;
            const started = currentData.matchList.find(x => x.number === s.number);
            if (started) {
                started.start = s.startAt;
            }
            break;
        case ScheduleUpdateType.MATCH_ABORT:
            const a = update.update as MatchAbort;
            const aborted = currentData.matchList.find(x => x.number === a.number)
            if (aborted) {
                aborted.start = -1;
            }
            break;
        case ScheduleUpdateType.TIMEOUT_DATA:
            const t = update.update as TimeoutData;
            currentData.nextMatch = t.assumedNext?.length > 0 ? currentData.matchList.find(x => x.number === t.assumedNext[0]?.number) : undefined;
            currentData.timeouts = t.activeTimeouts;
            break;
        default:
            console.warn("Unknown message type " + update.update.type);
            break;
    }
    return {
        ...current,
        [division]: currentData
    }
}

export default function DivisionTiming({eventCode, divisionNames}: {eventCode: string, divisionNames: string[]}) {
    const [data, dispatchUpdate] = useReducer((current: Record<number, MatchTimingData>, data: DivTimingUpdate) => updateDivData(current, data), {})
    const { isConnected, now: nowCallback, send } = usePersistentWebsocketWithTime(
        `/stream/divTiming/?code=${eventCode}`, dispatchUpdate);

    return <div><MultiDivisionTimingTab divisionTimeoutData={data} divisionNames={divisionNames} nowCallback={nowCallback} isHr={false}/></div>
}